import React from "react";
import Marquee from "react-fast-marquee";
import img1 from "./images/one.png";
import img2 from "./images/two.png";
import img3 from "./images/three.png";
import img4 from "./images/four.png";
import img5 from "./images/five.png";
import img6 from "./images/six.png";
import img7 from "./images/seven.png";
import img8 from "./images/eight.png";
import img9 from "./images/nine.png";
import img10 from "./images/ten.png";
import "./App.css";

function App() {
  return (
    <div className="App">
      <div className="title">
        <h1>Our Technology Partner</h1>
      </div>

      <div>
        <Marquee direction="right" speed={100} delay={2}>
          <div className="examples">
            <div
              className="marquee-container"
              style="
        margin-top: 50px;
        --pause-on-hover: running;
        --pause-on-click: running;
        --width: 100%;
        --transform: none;
      "
            >
              <div
                className="marquee"
                style="
          --play: running;
          --direction: normal;
          --duration: 80s;
          --delay: 0s;
          --iteration-count: infinite;
          --min-width: auto;
        "
              >
                <div className="initial-child-container">
                  <div className="child" style="--transform: none">
                    <div className="card">
                      <img alt="" src={img1} width="100" height="100" />
                      <p style="margin-top: 5px; margin-bottom: 0px">
                        Lorem ipsum dolor sit amet, consectetur adipiscing elit,
                        sed do eiusmod tempor incididunt ut labore et dolore
                        magna aliqua. Ut enim ad minim veniam.
                      </p>
                    </div>
                  </div>
                  <div className="child" style="--transform: none">
                    <div className="card">
                      <img alt="" src={img2} width="100" height="100" />
                      <p style="margin-top: 5px; margin-bottom: 0px">
                        Lorem ipsum dolor sit amet, consectetur adipiscing elit,
                        sed do eiusmod tempor incididunt ut labore et dolore
                        magna aliqua. Ut enim ad minim veniam.
                      </p>
                    </div>
                  </div>
                  <div className="child" style="--transform: none">
                    <div className="card">
                      <img alt="" src={img3} width="100" height="100" />
                      <p style="margin-top: 5px; margin-bottom: 0px">
                        Lorem ipsum dolor sit amet, consectetur adipiscing elit,
                        sed do eiusmod tempor incididunt ut labore et dolore
                        magna aliqua. Ut enim ad minim veniam.
                      </p>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </Marquee>
      </div>
    </div>
  );
}

export default App;
